        overflow: hidden;
        border: 4px solid #b8860b;
        box-shadow: inset 0 0 0 3px #080c18, inset 0 0 0 5px #ffd700;
    }
    .style-fortune .arch-frame::after {
        content: ''; position: absolute; top: 0; left: 0; width: 100%; height: 100%;
        border-radius: 160px 160px 12px 12px;
        border: 4px solid rgba(255, 215, 0, 0.4);
        mask-image: linear-gradient(45deg, transparent 40%, black 50%, transparent 60%);
        -webkit-mask-image: linear-gradient(45deg, transparent 40%, black 50%, transparent 60%);
        mask-size: 200%; -webkit-mask-size: 200%;
        animation: shineBorder 4s infinite linear; pointer-events: none; z-index: 5;
    }
    .style-fortune .stars-bg { position: absolute; top: 0; left: 0; width: 100%; height: 100%; z-index: 0; pointer-events: none; }
    .style-fortune .zodiac-ring { position: absolute; top: 35%; left: 50%; width: 400px; height: 400px; background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 100 100' xmlns='http://www.w3.org/2000/svg'%3E%3Ccircle cx='50' cy='50' r='49' fill='none' stroke='rgba(255,215,0,0.08)' stroke-width='0.5' stroke-dasharray='2'/%3E%3Ccircle cx='50' cy='50' r='35' fill='none' stroke='rgba(255,215,0,0.05)' stroke-width='2'/%3E%3Cpath d='M50 0 L50 100 M0 50 L100 50' stroke='rgba(255,215,0,0.05)' stroke-width='0.5'/%3E%3C/svg%3E"); transform: translate(-50%, -50%); animation: rotateZodiac 120s linear infinite; }
    .style-fortune .stardust { position: absolute; background: #fff; border-radius: 50%; box-shadow: 0 0 4px #fff, 0 0 8px rgba(255, 215, 0, 0.5); opacity: 0; animation: twinkle 3s infinite ease-in-out; }
    .style-fortune .content-layout { position: relative; z-index: 2; display: flex; flex-direction: column; align-items: center; text-align: center; padding: 60px 30px 40px 30px; height: 100%; color: #e0d2b4; }
    .style-fortune .top-icon { font-size: 2em; color: #ffd700; margin-bottom: 20px; opacity: 0.9; filter: drop-shadow(0 0 10px rgba(255, 215, 0, 0.6)); }
    .style-fortune .arch-num { font-family: 'Cinzel', serif; font-size: 1em; letter-spacing: 4px; color: #8a9bbd; margin-bottom: 10px; }
    .style-fortune .arch-title { font-family: 'Cinzel', serif; font-size: 1.8em; font-weight: 700; line-height: 1.2; text-transform: uppercase; margin-bottom: 30px; background: linear-gradient(to bottom, #fff, #ffd700); -webkit-background-clip: text; -webkit-text-fill-color: transparent; filter: drop-shadow(0 2px 4px rgba(0,0,0,0.5)); }
    .style-fortune .arch-text-area { margin-top: auto; width: 100%; background: rgba(0, 0, 0, 0.4); border-top: 1px solid rgba(255, 215, 0, 0.3); padding: 20px 10px; border-radius: 8px; backdrop-filter: blur(2px); }
    .style-fortune .keywords { font-size: 0.8em; color: #81cdf8; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 10px; font-weight: 700; }
    .style-fortune .description { font-family: 'Noto Serif SC', serif; font-size: 0.95em; line-height: 1.7; color: #dce5f2; font-style: italic; }
    @keyframes hoverFloat { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-10px); } }
    @keyframes rotateZodiac { from { transform: translate(-50%, -50%) rotate(0deg); } to { transform: translate(-50%, -50%) rotate(360deg); } }
    @keyframes shineBorder { 0% { -webkit-mask-position: 200%; } 100% { -webkit-mask-position: -200%; } }
    @keyframes twinkle { 0%, 100% { opacity: 0; transform: scale(0.2); } 50% { opacity: 1; transform: scale(1.2); } }
</style>
